// This file closes coverage gap F-2: every tenant-scoped RLS table must have an
// isolation regression test, not just the handful with hand-written per-domain
// tests. Policies for these tables are generated by shared migration loops, so
// uniformity is high — but nothing else fails when a newly added table forgets
// FORCE ROW LEVEL SECURITY or ships an asymmetric USING/WITH CHECK. The table
// below drives testkit.AssertRLSIsolationSeeded (the real four-property probe)
// over the full census, and TestIntegrationRLSCensusComplete makes the list
// self-maintaining: adding a tenant-scoped RLS table without registering it here
// (or explicitly excluding it) fails the suite.

// rlsProbeTable names a tenant-scoped RLS table and builds one minimal probe row
// for it (EXCLUDING tenant_id, which AssertRLSIsolationSeeded supplies).
type rlsProbeTable struct {
	name string
	// platformWritten marks tables that only app_platform (not app_rt) may
	// write — authz config, audit anchors, integration/webhook config. Their
	// isolation is probed under app_platform, the role that operates them.
	platformWritten bool
	// row returns the non-tenant columns of one probe row. It may seed FK parents
	// via the Admin pool (which bypasses RLS, like a platform provisioner) and
	// return their ids. It is called once per insert, so id/unique columns must
	// differ between calls — hence uuid.New()/randHex() for them.
	row func(t *testing.T, h *DBHandle, tenant uuid.UUID) map[string]any
}

// rlsExcluded are tenant-scoped RLS tables deliberately NOT covered by the
// uniform strict-isolation probe — each for a structurally verifiable reason
// (assertExcludable enforces the reason, so a table cannot dodge the probe just
// by being listed here). Grouped by reason for documentation only.
var rlsExcluded = []string{
	// Hybrid catalog/config tables: either a RESTRICTIVE secondary policy
	// (owner/platform write) layered on tenant isolation, or a LOOSE tenant
	// policy — app_tenant_id_or_null() / "tenant_id IS NULL" shared rows, or a
	// permissive platform-write policy — rather than simple per-tenant isolation.
	"document_access_grants",
	"integration_providers",
	"notification_templates",
	"policies",
	"roles",
	"rule_versions",
	"audit_anchors",
	// Grant-only tables: app_rt has no direct per-tenant SELECT path; they are
	// driven by privileged job workers and covered by their own tests.
	"jobs_queue",
	"job_runs",
	"identity_grant",
}

