// TestIntegrationRLSIsolationAllTenantTables runs the full four-property RLS
// probe over every tenant-scoped RLS table in the census. It fails if any table
// loses FORCE RLS or its USING/WITH CHECK symmetry (a leaked cross-tenant read
// or an accepted cross-tenant write).
func TestIntegrationRLSIsolationAllTenantTables(t *testing.T) {
	h := NewDB(t)
	tables := tenantScopedRLSProbeTables()

	for _, tbl := range tables {
		t.Run(tbl.name, func(t *testing.T) {
			// FORCE RLS is invisible to a probe run as app_rt/app_platform (both are
			// non-owners, always subject to RLS). Assert it structurally so a table
			// that drops FORCE — letting its owner bypass isolation — is caught.
			assertForceRLS(t, h, tbl.name)

			tenantA := CreateTenant(t, h).ID
			tenantB := CreateTenant(t, h).ID
			writeTxM := h.TxM
			if tbl.platformWritten {
				writeTxM = h.PlatformTxM
			}
			factory := tbl.row
			AssertRLSIsolationSeeded(t, h, tbl.name, tenantA, tenantB,
				func(tenant uuid.UUID) map[string]any { return factory(t, h, tenant) }, writeTxM)
		})
	}
}

// TestIntegrationRLSCensusComplete makes the probe list self-maintaining: it
// compares the hard-coded census (probe list ∪ RESTRICTIVE-excluded) against the
// live set of tenant-scoped RLS tables and fails on any drift, so a newly added
// table cannot silently escape isolation testing.
//
// It also guards BOTH directions structurally via assertExcludable: every
// excluded table must genuinely be non-strict (RESTRICTIVE policy, a loose
// tenant policy, or no app_rt read path), and every PROBED table must genuinely
// be strict. So a table cannot dodge the probe by being listed as excluded, and
// a probed table that is later loosened (e.g. switched to app_tenant_id_or_null)
// fails here even if the behavioral probe still happens to pass.
func TestIntegrationRLSCensusComplete(t *testing.T) {
	h := NewDB(t)

	live := liveTenantScopedRLSTables(t, h)

	covered := map[string]bool{}
	for _, tbl := range tenantScopedRLSProbeTables() {
		if covered[tbl.name] {
			t.Errorf("duplicate table %q in tenantScopedRLSProbeTables", tbl.name)
		}
		covered[tbl.name] = true
	}
	excluded := map[string]bool{}
	for _, name := range rlsExcluded {
		if excluded[name] {
			t.Errorf("duplicate table %q in rlsExcluded", name)
		}
		excluded[name] = true
	}

	// Every live tenant-scoped RLS table must be either probed or explicitly excluded.
	for name := range live {
		if !covered[name] && !excluded[name] {
			t.Errorf("tenant-scoped RLS table %q is not covered: add it to tenantScopedRLSProbeTables "+
				"(or, if it is a hybrid/grant-only table, to rlsExcluded)", name)
		}
	}
	// Every registered/excluded table must still be a live tenant-scoped RLS table
	// (else it was renamed or lost RLS and the list is stale).
	for name := range covered {
		if !live[name] {
			t.Errorf("probed table %q is not a live tenant-scoped RLS table (renamed or lost RLS?)", name)
		}
	}
	for name := range excluded {
		if !live[name] {
			t.Errorf("excluded table %q is not a live tenant-scoped RLS table (renamed or lost RLS?)", name)
		}
	}

	// Anti-dodge, both directions: excluded tables must be non-strict; probed
	// tables must be strict.
	for name := range excluded {
		if live[name] && !isExcludable(t, h, name) {
			t.Errorf("table %q is in rlsExcluded but is a strict per-tenant table — it must be probed, not excluded", name)
		}
	}
	for name := range covered {
		if live[name] && isExcludable(t, h, name) {
			t.Errorf("table %q is probed as strict per-tenant but the catalog shows it is hybrid/loose/grant-only — "+
				"move it to rlsExcluded (or restore its strict tenant policy)", name)
		}
	}

	t.Logf("RLS census: %d live tenant-scoped tables = %d strict-probed + %d excluded",
		len(live), len(covered), len(excluded))
}

// isExcludable reports whether a tenant-scoped RLS table is NOT a simple,
// strictly-isolated per-tenant table, using only the live catalog. A table is
// excludable when any of the following holds:
//   - it carries a RESTRICTIVE policy (secondary owner/platform-write gate);
//   - it has a LOOSE tenant policy — one referencing app_tenant_id_or_null() or
//     "tenant_id IS NULL" (shared platform rows / fail-to-empty), which breaks
//     the strict fail-closed contract;
//   - app_rt cannot SELECT it (grant-only: no per-tenant read path); or
//   - app_rt cannot INSERT it yet it has a permissive USING/CHECK "true" policy,
//     i.e. its write role bypasses the WITH CHECK tenant gate (audit anchors).
func isExcludable(t *testing.T, h *DBHandle, table string) bool {
	t.Helper()
	var restrictive, nullish, truePerm, appRTSelect, appRTInsert bool
	err := h.Admin.QueryRow(context.Background(), `
		SELECT
		  EXISTS (SELECT 1 FROM pg_policies p WHERE p.schemaname='public' AND p.tablename=$1 AND p.permissive='RESTRICTIVE'),
		  EXISTS (SELECT 1 FROM pg_policies p WHERE p.schemaname='public' AND p.tablename=$1
		           AND (p.qual LIKE '%app_tenant_id_or_null%' OR p.with_check LIKE '%app_tenant_id_or_null%'
		             OR p.qual LIKE '%tenant_id IS NULL%' OR p.with_check LIKE '%tenant_id IS NULL%')),
		  EXISTS (SELECT 1 FROM pg_policies p WHERE p.schemaname='public' AND p.tablename=$1
		           AND p.permissive='PERMISSIVE' AND (p.qual='true' OR p.with_check='true')),
		  EXISTS (SELECT 1 FROM information_schema.role_table_grants g WHERE g.table_schema='public'
		           AND g.table_name=$1 AND g.grantee='app_rt' AND g.privilege_type='SELECT'),
		  EXISTS (SELECT 1 FROM information_schema.role_table_grants g WHERE g.table_schema='public'
		           AND g.table_name=$1 AND g.grantee='app_rt' AND g.privilege_type='INSERT')`,
		table).Scan(&restrictive, &nullish, &truePerm, &appRTSelect, &appRTInsert)
	if err != nil {
		t.Fatalf("classify %s: %v", table, err)
	}
	return restrictive || nullish || !appRTSelect || (!appRTInsert && truePerm)
}

// assertForceRLS fails unless the table has both ROW LEVEL SECURITY enabled and
// FORCED (so even the table owner is subject to the policies).
func assertForceRLS(t *testing.T, h *DBHandle, table string) {
	t.Helper()
	var enabled, forced bool
	if err := h.Admin.QueryRow(context.Background(),
		`SELECT c.relrowsecurity, c.relforcerowsecurity
		   FROM pg_class c JOIN pg_namespace n ON n.oid = c.relnamespace
		  WHERE n.nspname = 'public' AND c.relname = $1`, table).Scan(&enabled, &forced); err != nil {
		t.Fatalf("query pg_class for %s: %v", table, err)
	}
	if !enabled {
		t.Errorf("table %q does not have ROW LEVEL SECURITY enabled", table)
	}
	if !forced {
		t.Errorf("table %q does not FORCE ROW LEVEL SECURITY (owner can bypass tenant isolation)", table)
	}
}

// liveTenantScopedRLSTables returns the authoritative live set: public tables
// with RLS enabled that carry a tenant_id column.
func liveTenantScopedRLSTables(t *testing.T, h *DBHandle) map[string]bool {
	t.Helper()
	rows, err := h.Admin.Query(context.Background(), `
		SELECT c.relname
		  FROM pg_class c
		  JOIN pg_namespace n ON n.oid = c.relnamespace
		 WHERE n.nspname = 'public' AND c.relrowsecurity
		   AND EXISTS (SELECT 1 FROM information_schema.columns col
		                WHERE col.table_schema = 'public' AND col.table_name = c.relname
		                  AND col.column_name = 'tenant_id')`)
	if err != nil {
		t.Fatalf("query live tenant-scoped RLS tables: %v", err)
	}
	defer rows.Close()

	set := map[string]bool{}
	for rows.Next() {
		var name string
		if err := rows.Scan(&name); err != nil {
			t.Fatalf("scan table name: %v", err)
		}
		set[name] = true
	}
	if err := rows.Err(); err != nil {
		t.Fatalf("iterate tenant-scoped RLS tables: %v", err)
	}
	return set
}

// --- FK-parent seed helpers (Admin pool bypasses RLS, like a provisioner) ---

func seedParty(t *testing.T, h *DBHandle, tenant uuid.UUID) uuid.UUID {
	t.Helper()
	id := uuid.New()
	execAdmin(t, h, `INSERT INTO parties (id, tenant_id, kind, display_name, created_by) VALUES ($1,$2,'person',$3,$4)`,
		id, tenant, "P "+randHex(4), uuid.Nil)
	return id
}

func seedDocument(t *testing.T, h *DBHandle, tenant uuid.UUID) uuid.UUID {
	t.Helper()
	id := uuid.New()
	execAdmin(t, h, `INSERT INTO documents (id, tenant_id, document_class, title, created_by) VALUES ($1,$2,'generic',$3,$4)`,
		id, tenant, "t", uuid.Nil)
	return id
}

func seedDocumentVersion(t *testing.T, h *DBHandle, tenant uuid.UUID) uuid.UUID {
	t.Helper()
	id := uuid.New()
	execAdmin(t, h, `INSERT INTO document_versions
		(id, tenant_id, document_id, version_no, storage_key, mime_type, size_bytes, checksum_sha256, uploaded_by)
		VALUES ($1,$2,$3,1,$4,'text/plain',1,$5,$6)`,
		id, tenant, seedDocument(t, h, tenant), "s/"+randHex(8), randHex(16), uuid.Nil)
	return id
}

