// randInt63 returns a non-negative pseudo-unique 62-bit int for columns that
// only need to differ between the two probe inserts (e.g. audit sequences).
func randInt63() int64 {
	b := randHex(15) // 60 bits
	var v int64
	for _, c := range b {
		v <<= 4
		switch {
		case c >= '0' && c <= '9':
			v |= int64(c - '0')
		default:
			v |= int64(c-'a') + 10
		}
	}
	if v < 0 {
		v = -v
	}
	return v
}
